#include<stdio.h>
#include<string.h>
char v[1001][20];int n=0;
int bh(int i,int par_red){
  if(i>=n||strcmp(v[i],"N")==0)return 0;
  int red=v[i][0]=='R';
  if(par_red&&red)return-1;
  int lh=bh(2*i+1,red),rh=bh(2*i+2,red);
  if(lh<0||rh<0||lh!=rh)return-1;
  return lh+(red?0:1);
}
int main(){while(scanf("%s",v[n])==1)n++;if(strcmp(v[0],"N")==0){puts("YES 0");return 0;}if(v[0][0]=='R'){puts("NO");return 0;}int h=bh(0,0);if(h<0)puts("NO");else printf("YES %d\n",h);}
